	@Test
	void approveAllBulkFailureDoesNotMutateNonIsolatedEstimatorBeforeStoreSuccess() throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc");
		setBulkOperationSize(config, 2);
		LmdbStore sail = new LmdbStore(new File(dataDir, "bulk-failure-estimator"), config);
		sail.init();

		try {
			LmdbSailStore backingStore = sail.getBackingStore();
			backingStore.enableMultiThreading = false;
			SketchBasedJoinEstimator estimator = backingStore.getSketchBasedJoinEstimator();
			try (SailSink seedSink = backingStore.getExplicitSailSource().sink(IsolationLevels.NONE)) {
				seedSink.approveAll(sampleStatements(5), Set.of());
				seedSink.flush();
			}
			estimator.rebuild();
			assertTrue("Expected estimator to be ready before the failed bulk add", estimator.isReady());

			Field tripleStoreField = LmdbSailStore.class.getDeclaredField("tripleStore");
			tripleStoreField.setAccessible(true);
			TripleStore originalTripleStore = (TripleStore) tripleStoreField.get(backingStore);
			TripleStore tripleStoreSpy = spy(originalTripleStore);

			doAnswer(invocation -> {
				IntConsumer addedIndexConsumer = invocation.getArgument(6);
				addedIndexConsumer.accept(0);
				throw new IOException("expected aligned bulk failure after estimator update");
			}).when(tripleStoreSpy)
					.storeTriplesAligned(any(long[].class), any(long[].class), any(long[].class),
							any(long[].class), anyInt(), anyBoolean(), any(IntConsumer.class));

			tripleStoreField.set(backingStore, tripleStoreSpy);
			try (SailSink sink = backingStore.getExplicitSailSource().sink(IsolationLevels.NONE)) {
				assertThrows(SailException.class, () -> sink.approveAll(sampleStatements(2), Set.of()));

				assertTrue("Estimator should remain ready because bulk additions are recorded after store success",
						estimator.isReady());
			} finally {
				tripleStoreField.set(backingStore, originalTripleStore);
			}
		} finally {
			sail.shutDown();
		}
	}

	@Test
	void estimatorStatementScanDoesNotBlockWritesAfterSnapshotOpen() throws Exception {
		LmdbStore sail = (LmdbStore) ((SailRepository) repo).getSail();
		SketchBasedJoinEstimator estimator = sail.getBackingStore().getSketchBasedJoinEstimator();
		SketchStatementSource statementSource = getEstimatorStatementSource(estimator);

		CountDownLatch iterationOpened = new CountDownLatch(1);
		CountDownLatch releaseIteration = new CountDownLatch(1);
		AtomicReference<Throwable> scannerFailure = new AtomicReference<>();
		Thread scanner = new Thread(() -> {
			try (CloseableIteration<? extends Statement> statements = statementSource.getStatements(null, null, null)) {
				assertTrue("Expected estimator statement source to open a non-empty snapshot", statements.hasNext());
				iterationOpened.countDown();
				assertTrue("Timed out waiting to release estimator snapshot",
						releaseIteration.await(5, TimeUnit.SECONDS));
			} catch (Throwable t) {
				scannerFailure.set(t);
				iterationOpened.countDown();
			}
		}, SketchBasedJoinEstimator.REFRESH_THREAD_NAME);

		CountDownLatch writerFinished = new CountDownLatch(1);
		AtomicReference<Throwable> writerFailure = new AtomicReference<>();
		Thread writer = new Thread(() -> {
			try (RepositoryConnection conn = repo.getConnection()) {
				conn.setNamespace("scan", "urn:scan");
			} catch (Throwable t) {
				writerFailure.set(t);
			} finally {
				writerFinished.countDown();
			}
		}, "lmdb-estimator-scan-writer");

		try {
			scanner.start();
			assertTrue("Timed out opening estimator statement snapshot", iterationOpened.await(5, TimeUnit.SECONDS));
			if (scannerFailure.get() != null) {
				throw new AssertionError("Estimator scanner failed", scannerFailure.get());
			}

			writer.start();
			assertTrue("Estimator read snapshot should not hold the LMDB sink lock after opening the scan",
					writerFinished.await(1, TimeUnit.SECONDS));
			if (writerFailure.get() != null) {
				throw new AssertionError("Concurrent namespace write failed", writerFailure.get());
			}
		} finally {
			releaseIteration.countDown();
			scanner.join(5_000L);
			writer.join(5_000L);
		}
		assertFalse("Estimator scanner thread should have finished", scanner.isAlive());
		assertFalse("Concurrent writer thread should have finished", writer.isAlive());
	}

	private static SketchStatementSource getEstimatorStatementSource(SketchBasedJoinEstimator estimator)
			throws Exception {
		Field statementSourceField = SketchBasedJoinEstimator.class.getDeclaredField("statementSource");
		statementSourceField.setAccessible(true);
		return (SketchStatementSource) statementSourceField.get(estimator);
	}

	private static void setBulkOperationSize(LmdbStoreConfig config, int bulkOperationSize) {
		try {
			Method setter = config.getClass().getMethod("setBulkOperationSize", int.class);
			setter.invoke(config, bulkOperationSize);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("Missing LMDB bulk operation size config setter", e);
		}
	}

	private Set<Statement> sampleStatements(int count) {
		Set<Statement> statements = new LinkedHashSet<>();
		for (int i = 0; i < count; i++) {
			statements.add(F.createStatement(
					F.createIRI("urn:bulk:subject:" + i),
					F.createIRI("urn:bulk:predicate:" + (i % 3)),
					F.createIRI("urn:bulk:object:" + (i % 5)),
					F.createIRI("urn:bulk:context:" + (i % 2))));
		}
		return statements;
	}

	private static long invocationCount(Object mock, String methodName) {
		return mockingDetails(mock).getInvocations()
				.stream()
				.filter(invocation -> methodName.equals(invocation.getMethod().getName()))
				.count();
	}

	private static int onlyInvocationIntArgument(Object mock, String methodName, int argumentIndex) {
		return mockingDetails(mock).getInvocations()
				.stream()
				.filter(invocation -> methodName.equals(invocation.getMethod().getName()))
				.map(invocation -> (Integer) invocation.getArgument(argumentIndex))
				.findFirst()
				.orElseThrow(() -> new AssertionError("Expected invocation of " + methodName));
	}

	private static boolean booleanField(Object target, String fieldName) throws Exception {
		Field field = target.getClass().getDeclaredField(fieldName);
		field.setAccessible(true);
		return field.getBoolean(target);
	}

	private static boolean reachesWaitState(Thread thread, long timeoutMillis) {
		long deadline = System.nanoTime() + TimeUnit.MILLISECONDS.toNanos(timeoutMillis);
		while (System.nanoTime() < deadline) {
			Thread.State state = thread.getState();
			if (state == Thread.State.WAITING || state == Thread.State.TIMED_WAITING) {
				return true;
			}
			if (!thread.isAlive()) {
				return false;
			}
			Thread.onSpinWait();
		}
		return false;
	}

